def count_distinct_pairs(nums, target):
    pairs = set()
    for i in range(len(nums)):
        for j in range(i, len(nums)):
            pair_sum = nums[i] + nums[j]
            if pair_sum == target:
                pairs.add((min(nums[i], nums[j]), max(nums[i], nums[j])))
    return len(pairs)
